// frontend/src/components/jobs/JobList.jsx
import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    const containerStyle = {
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: '24px',
        width: '100%'
    };

    const safeJobs = Array.isArray(jobs) ? jobs : [];

    return (
        <div style={containerStyle}>
            {safeJobs.map((job) => {
                // DEBUG: Mari kita pastikan job.id benar-benar ada
                if (!job.id) {
                    console.warn("Data pekerjaan ini tidak memiliki ID:", job);
                }

                return (
                    <div key={job.id || Math.random()}> 
                        <JobCard 
                            job={job} 
                            isFull={variant === 'full'} 
                            onClick={() => onSelectJob && onSelectJob(job)}
                        />
                    </div>
                );
            })}
        </div>
    );
};

export default JobList;
